def lookup(third_groups: list[str]) -> dict[str, str] | None:
    """
    Dado el conjunto de 8 grupos que aportan terceros clasificados,
    devuelve {codigo_partido: letra_grupo} segun la matriz oficial FIFA.
    Devuelve None si no hay exactamente 8 grupos o no existe la combinacion.
    """
    if len(third_groups) != 8:
        return None
    key = tuple(sorted(third_groups))
    return THIRD_PLACE_MATRIX.get(key)
